import base64
import requests
from lxml import etree
from xml.etree.ElementTree import Element, SubElement, tostring

class SAMLServiceProvider:
    def __init__(self, destination_url, user_info):
        self.destination_url = destination_url
        self.user_info = user_info

    def create_authn_request(self):
        root = Element('s:AuthnRequest', {
            'xmlns:s': 'urn:oasis:names:tc:SAML:2.0:protocol',
            'ID': 'id123',
            'Version': '2.0',
            'IssueInstant': '2023-10-01T00:00:00Z',
            'Destination': self.destination_url,
            'ProtocolBinding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST',
            'AssertionConsumerServiceURL': 'https://yourapp.com/consume'
        })

        issuer = SubElement(root, 's:Issuer')
        issuer.text = 'your-sp-entity-id'

        name_id_policy = SubElement(root, 's:NameIDPolicy', {
            'Format': 'urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified',
            'AllowCreate': 'true'
        })

        name_id = SubElement(name_id_policy, 's:NameID')
        name_id.text = self.user_info['username']

        return tostring(root, encoding='utf-8')

    def send_request(self):
        request_xml = self.create_authn_request()
        encoded_request = base64.b64encode(request_xml).decode('utf-8')
        
        response = requests.post(
            self.destination_url,
            data={'SAMLRequest': encoded_request}
        )
        
        return response


